#!/usr/bin/env node

// generate-icon-bundle.mjs
// Fetches Material Symbol SVGs and generates a TypeScript bundle
// Usage: node scripts/generate-icon-bundle.mjs

import { readFileSync, writeFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, '..');

const ICONS_SOURCE = resolve(ROOT, 'assets/map-icons.ts');
const OUTPUT_FILE = resolve(ROOT, 'assets/map-icons-svg-bundle.ts');
const BASE_URL = 'https://fonts.gstatic.com/s/i/short-term/release/materialsymbolsoutlined';

/** Extract unique icon names from the defaultCategoryIcons object in map-icons.ts */
function extractIconNames() {
  const source = readFileSync(ICONS_SOURCE, 'utf-8');
  const matches = source.matchAll(/icon:\s*'([^']+)'/g);
  const icons = new Set([...matches].map(m => m[1]));
  icons.add('place'); // Always include the fallback icon
  return [...icons].sort();
}

/** Fetch a single SVG from the Material Symbols CDN */
async function fetchSvg(iconName) {
  const url = `${BASE_URL}/${iconName}/default/24px.svg`;
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Failed to fetch ${iconName}: HTTP ${response.status}`);
  }
  const text = await response.text();
  if (!text.trimStart().startsWith('<svg')) {
    throw new Error(`Invalid SVG for ${iconName}: ${text.slice(0, 50)}`);
  }
  return text.trim();
}

async function main() {
  const iconNames = extractIconNames();
  console.log(`Fetching ${iconNames.length} unique icons...`);

  const entries = [];
  const failures = [];

  // Fetch in batches of 10 to avoid hammering the CDN
  for (let i = 0; i < iconNames.length; i += 10) {
    const batch = iconNames.slice(i, i + 10);
    const results = await Promise.allSettled(
      batch.map(async (name) => {
        const svg = await fetchSvg(name);
        return { name, svg };
      })
    );
    for (const result of results) {
      if (result.status === 'fulfilled') {
        entries.push(result.value);
      } else {
        failures.push(result.reason.message);
      }
    }
  }

  if (failures.length > 0) {
    console.error('Failures:', failures);
    process.exit(1);
  }

  entries.sort((a, b) => a.name.localeCompare(b.name));

  const now = new Date().toISOString();
  const lines = [
    `// AUTO-GENERATED by scripts/generate-icon-bundle.mjs -- DO NOT EDIT`,
    `// Generated: ${now}`,
    `// Regenerate: npm run generate-icon-bundle`,
    `// Source: Google Material Symbols Outlined (Apache 2.0 license)`,
    ``,
    `/** Bundled Material Symbol SVGs, keyed by icon name */`,
    `export const iconSvgBundle: Record<string, string> = {`,
    ...entries.map(({ name, svg }) =>
      `  ${JSON.stringify(name)}: ${JSON.stringify(svg)},`
    ),
    `};`,
    ``,
  ];

  writeFileSync(OUTPUT_FILE, lines.join('\n'), 'utf-8');
  console.log(`Wrote ${entries.length} icons to ${OUTPUT_FILE}`);
}

main();
